function formatINR($num) {
    $num = (int)round($num);
    $str = (string)$num;
    $len = strlen($str);
    if ($len <= 3) return $str;
    $result = substr($str, -3);
    $str = substr($str, 0, -3);
    while (strlen($str) > 2) {
        $result = substr($str, -2) . ',' . $result;
        $str = substr($str, 0, -2);
    }
    if ($str) $result = $str . ',' . $result;
    return $result;
}

